            <h3 className="mb-6 text-lg font-semibold text-zinc-200">
              {group}
            </h3>
            <div className="flex flex-col gap-10">
              {samples.map((s) => (
                <SampleCard key={s.name} name={s.name} code={s.code} />
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

